-- Normalize event_program.image_url to public uploads path.
-- Same program title -> same deterministic image URL.
UPDATE event_program
SET image_url = CONCAT(
  'C:\\pupoo_workspace\\uploads\\event_program\\program_',
  LPAD(
    MOD(
      CRC32(COALESCE(NULLIF(TRIM(program_title), ''), CONCAT('program-', program_id))),
      260
    ) + 1,
    4,
    '0'
  ),
  '.jpg'
);

-- --------------------------------------------------------------------------
-- Event timeline rebalance for demo pages
-- - Ensure /event/current has 4 ONGOING events
-- - Ensure /event/upcoming has 12 PLANNED events
-- - Keep CANCELLED events untouched
-- --------------------------------------------------------------------------

-- 0) Reset non-cancelled events to ENDED with past dates (idempotent baseline)
UPDATE event
SET
  start_at = TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL (180 - event_id) DAY), '10:00:00'),
  end_at = TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL (179 - event_id) DAY), '18:00:00'),
  status = 'ENDED'
WHERE status <> 'CANCELLED';

-- 1) 4 events in progress (event_id: 53~56)
UPDATE event
SET
  start_at = CASE event_id
    WHEN 53 THEN TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL 2 DAY), '10:00:00')
    WHEN 54 THEN TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL 1 DAY), '09:30:00')
    WHEN 55 THEN TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL 3 DAY), '11:00:00')
    WHEN 56 THEN TIMESTAMP(CURDATE(), '09:00:00')
    ELSE start_at
  END,
  end_at = CASE event_id
    WHEN 53 THEN TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 1 DAY), '18:00:00')
    WHEN 54 THEN TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 2 DAY), '19:00:00')
    WHEN 55 THEN TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 1 DAY), '17:30:00')
    WHEN 56 THEN TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 2 DAY), '20:00:00')
    ELSE end_at
  END,
  status = 'ONGOING'
WHERE event_id IN (53,54,55,56)
  AND status <> 'CANCELLED';

-- 2) 12 upcoming events (event_id: 31~42)
UPDATE event
SET
  start_at = TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL (event_id - 30) DAY), '10:00:00'),
  end_at = TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL (event_id - 28) DAY), '18:00:00'),
  status = 'PLANNED'
WHERE event_id BETWEEN 31 AND 42
  AND status <> 'CANCELLED';

-- 3) Organizer contacts (deterministic sample data for v5.8)
-- Ensure columns exist even on versions that do not support
-- "ADD COLUMN IF NOT EXISTS".
SET @sql_add_organizer_phone = (
  SELECT IF(
    EXISTS (
      SELECT 1
      FROM information_schema.COLUMNS
      WHERE TABLE_SCHEMA = DATABASE()
        AND TABLE_NAME = 'event'
        AND COLUMN_NAME = 'organizer_phone'
    ),
    'SELECT 1',
    'ALTER TABLE event ADD COLUMN organizer_phone VARCHAR(30) NULL'
  )
);
PREPARE stmt_add_organizer_phone FROM @sql_add_organizer_phone;
EXECUTE stmt_add_organizer_phone;
DEALLOCATE PREPARE stmt_add_organizer_phone;

SET @sql_add_organizer_email = (
  SELECT IF(
    EXISTS (
      SELECT 1
      FROM information_schema.COLUMNS
      WHERE TABLE_SCHEMA = DATABASE()
        AND TABLE_NAME = 'event'
        AND COLUMN_NAME = 'organizer_email'
    ),
    'SELECT 1',
    'ALTER TABLE event ADD COLUMN organizer_email VARCHAR(255) NULL'
  )
);
PREPARE stmt_add_organizer_email FROM @sql_add_organizer_email;
EXECUTE stmt_add_organizer_email;
DEALLOCATE PREPARE stmt_add_organizer_email;

UPDATE event
SET
  organizer_phone = CONCAT(
    CASE
      WHEN location LIKE '서울%' THEN '02'
      WHEN location LIKE '부산%' THEN '051'
      WHEN location LIKE '대구%' THEN '053'
      WHEN location LIKE '인천%' THEN '032'
      WHEN location LIKE '광주%' THEN '062'
      WHEN location LIKE '대전%' THEN '042'
      WHEN location LIKE '울산%' THEN '052'
      WHEN location LIKE '제주%' THEN '064'
      ELSE '031'
    END,
    '-',
    LPAD((event_id * 37) % 9000 + 1000, 4, '0'),
    '-',
    LPAD((event_id * 83) % 9000 + 1000, 4, '0')
  ),
  organizer_email = CONCAT('event', LPAD(event_id, 3, '0'), '@pupoo-event.kr')
WHERE organizer_phone IS NULL
   OR organizer_phone = ''
   OR organizer_email IS NULL
   OR organizer_email = '';
