INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (31, '2024 서울 펫 페스티벌 3회', '반려동물과 함께하는 서울 최대 규모의 펫 축제입니다. 100개 이상의 부스에서 최신 펫 용품을 만나보고, 전문 수의사 건강 상담부터 어질리티 대회, 패션쇼까지 다채로운 프로그램이 준비되어 있습니다.', '2024-03-13 10:00:00', '2024-03-16 16:00:00', '서울특별시 강남구 영동대로 513 코엑스', 'ENDED', 3, 15000, '서울특별시 반려동물협회');
