INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (42, '2025 고양 그루밍 체험전 3회', '반려견 그루밍에 특화된 체험 전시. 셀프 그루밍 체험존, 프로 그루머 시연, 피모 건강 진단 등을 제공합니다. 그루밍 도구 할인 판매도 진행됩니다.', '2025-01-14 10:00:00', '2025-01-17 16:00:00', '경기도 고양시 덕양구 화중로 104번길 꽃빛공원', 'ENDED', 3, 10000, '경기도 펫문화재단');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (43, '2025 춘천 반려견 캠핑 페스티벌 3회', '춘천 남이섬 인근에서 열리는 반려견 캠핑 페스티벌. 캠핑장 반려견 에티켓 교육, 야외 요리 교실, 별자리 관측 등 아웃도어 프로그램이 가득합니다.', '2025-01-03 10:00:00', '2025-01-04 18:00:00', '강원도 춘천시 남산면 남이섬길 1', 'ENDED', 3, 30000, '강원도 펫산업진흥원');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (44, '2025 전주 한옥마을 펫 산책 투어 3회', '전주 한옥마을에서 반려견과 함께하는 문화 산책. 한복 펫 포토, 전통 떡 만들기(견주용), 반려견 한방 건강 체크 등의 프로그램이 운영됩니다.', '2025-03-25 10:00:00', '2025-03-27 19:00:00', '전라북도 전주시 완산구 기린대로 99', 'ENDED', 3, 8000, '전라북도 동물복지포럼');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (45, '2025 세종 반려동물 복지 포럼 3회', '세종시에서 개최하는 반려동물 복지 정책 토론회. 동물보호법 개정 동향, 펫 보험 제도 현황, 동물등록 시스템 개선 등을 주제로 전문가 패널 토론이 진행됩니다.', '2025-07-13 09:00:00', '2025-07-16 19:00:00', '세종특별자치시 보람상무로 세종컨벤션센터', 'ENDED', 3, 0, '세종특별자치시 반려생활연구회');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (46, '2025 서울 펫 페스티벌 4회', '반려동물과 함께하는 서울 최대 규모의 펫 축제입니다. 100개 이상의 부스에서 최신 펫 용품을 만나보고, 전문 수의사 건강 상담부터 어질리티 대회, 패션쇼까지 다채로운 프로그램이 준비되어 있습니다.', '2025-06-04 09:00:00', '2025-06-07 18:00:00', '서울특별시 강남구 영동대로 513 코엑스', 'ENDED', 4, 15000, '서울특별시 반려동물협회');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (47, '2025 부산 해운대 독 페스타 4회', '해운대 해변에서 열리는 반려견 전용 페스티벌. 해변 어질리티, 서핑 독 체험, 모래성 만들기 등 바다와 함께하는 특별한 경험을 제공합니다. 부산 지역 유명 펫카페 출장 부스도 운영됩니다.', '2025-12-08 09:00:00', '2025-12-09 17:00:00', '부산광역시 해운대구 해운대해변로 264', 'ENDED', 4, 12000, '부산광역시 펫문화재단');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (48, '2025 제주 반려견 힐링 캠프 4회', '제주 자연 속에서 반려견과 함께 힐링하는 3일간의 캠프. 오름 트레킹, 숲속 산책, 반려견 요가 등 자연 친화적 프로그램으로 구성됩니다. 제주 로컬 간식 시식회도 준비됩니다.', '2025-12-18 10:00:00', '2025-12-21 19:00:00', '제주특별자치도 서귀포시 중문관광로 72번길 35', 'ENDED', 4, 35000, '제주특별자치도 펫산업진흥원');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (49, '2025 경기 킨텍스 펫쇼 4회', '국내 최대 규모 반려동물 산업 전시회. 글로벌 펫푸드 브랜드부터 스마트 펫테크 스타트업까지 200여 업체가 참가합니다. B2B 세션과 일반 관람 동시 진행.', '2025-04-15 10:00:00', '2025-04-16 18:00:00', '경기도 고양시 일산서구 킨텍스로 217-60 킨텍스 제1전시장', 'ENDED', 4, 20000, '경기도 동물복지포럼');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (50, '2025 대구 반려견 운동회 4회', '대구 시민 공원에서 열리는 반려견 가족 운동회. 달리기 대회, 줄다리기, 보물찾기 등 반려견과 보호자가 함께 즐기는 팀 경기를 진행합니다.', '2025-12-25 09:00:00', '2025-12-26 18:00:00', '대구광역시 달서구 두류공원로 160', 'ENDED', 4, 8000, '대구광역시 반려생활연구회');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (51, '2025 인천 유기동물 입양 박람회 4회', '인천 지역 보호소와 구조단체가 함께하는 입양 박람회. 입양 상담, 임시보호 안내, 중성화 수술 지원 정보 등을 제공합니다. 입양 가족을 위한 기본 용품 키트도 제공됩니다.', '2025-01-08 09:00:00', '2025-01-09 15:00:00', '인천광역시 연수구 아카데미로 도림체육관', 'ENDED', 4, 0, '인천광역시 반려동물협회');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (52, '2025 대전 반려동물 건강 세미나 4회', '대전 컨벤션센터에서 열리는 반려동물 건강 전문 세미나. 수의학 교수진과 동물행동학자가 참여하여 만성질환 관리, 행동교정, 영양학 등을 주제로 강연합니다.', '2025-08-20 09:00:00', '2025-08-21 15:00:00', '대전광역시 유성구 도룡동 대전컨벤션센터', 'ENDED', 4, 25000, '대전광역시 펫문화재단');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (53, '2025 광주 댕댕이 마라톤 4회', '광주 시민과 반려견이 함께 달리는 5km 마라톤 대회. 완주 메달과 기념 반다나가 제공되며, 결승선에서는 포토존과 간식 부스가 운영됩니다.', '2025-04-18 09:00:00', '2025-04-19 16:00:00', '광주광역시 서구 상무시민공원', 'ENDED', 4, 10000, '광주광역시 펫산업진흥원');
INSERT INTO event (event_id,event_name,description,start_at,end_at,location,status,round_no,base_fee,organizer) VALUES (54, '2025 울산 반려견 어질리티 챌린지 4회', '전국 어질리티 마니아가 모이는 공식 대회. 초급·중급·고급 코스별로 진행되며, 입상자에게는 트로피와 상금이 수여됩니다. 초보자를 위한 체험 레인도 별도 운영.', '2025-05-08 10:00:00', '2025-05-11 20:00:00', '울산광역시 남구 삼산동 울산종합운동장', 'ENDED', 4, 18000, '울산광역시 동물복지포럼');
