INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (1,1,'SESSION','펫테크 신기술 소개','전문 수의사가 계절별 건강관리 포인트를 안내합니다. 예방접종, 기생충 관리, 피부 관리 등 실용적인 정보를 제공합니다.','2023-11-10 01:00:00','2023-11-10 03:00:00',5, 'C\\pupoo_workspace\\uploads\\event_program\\session_default.jpg','2023-11-04 09:00:00');
INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (2,1,'EXPERIENCE','수제 간식 만들기','장애물 코스를 반려견과 함께 도전합니다. 초보자도 즐길 수 있는 낮은 난이도의 체험 코스입니다.','2023-11-09 16:00:00','2023-11-09 17:00:00',1, 'C\\pupoo_workspace\\uploads\\event_program\\experience_default.jpg','2023-11-04 09:00:00');
INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (3,1,'EXPERIENCE','반려견 요가 체험','천연 재료로 건강한 반려견 간식을 직접 만들어봅니다. 완성된 간식은 포장하여 가져갈 수 있습니다.','2023-11-10 01:00:00','2023-11-10 02:00:00',1, 'C\\pupoo_workspace\\uploads\\event_program\\experience_default.jpg','2023-10-27 09:00:00');
INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (4,1,'CONTEST','수영 독 챔피언십','반려견과 보호자의 패션 센스를 뽐내는 무대입니다. 테마는 자유이며, 창의성과 반려견과의 조화를 심사합니다.','2023-11-11 07:00:00','2023-11-11 08:00:00',2, 'C\\pupoo_workspace\\uploads\\event_program\\contest_default.jpg','2023-10-29 09:00:00');
INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (5,1,'SESSION','반려동물 구강관리 특강','전문 수의사가 계절별 건강관리 포인트를 안내합니다. 예방접종, 기생충 관리, 피부 관리 등 실용적인 정보를 제공합니다.','2023-11-10 19:00:00','2023-11-10 21:00:00',5, 'C\\pupoo_workspace\\uploads\\event_program\\session_default.jpg','2023-10-29 09:00:00');
