INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (142,36,'CONTEST','최고의 재주꾼 선발대회','참가견의 미모와 매력을 겨루는 대회입니다. 견종별로 진행되며, 심사위원 평가와 관객 투표를 통해 수상자를 선정합니다.','2024-10-06 11:00:00','2024-10-06 13:00:00',194, 'C\\pupoo_workspace\\uploads\\event_program\\contest_default.jpg','2024-09-29 09:00:00');
INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (143,36,'SESSION','펫테크 신기술 소개','전문 수의사가 계절별 건강관리 포인트를 안내합니다. 예방접종, 기생충 관리, 피부 관리 등 실용적인 정보를 제공합니다.','2024-10-04 11:00:00','2024-10-04 13:00:00',191, 'C\\pupoo_workspace\\uploads\\event_program\\session_default.jpg','2024-09-25 09:00:00');
