INSERT INTO event_program (program_id,event_id,category,program_title,description,start_at,end_at,booth_id,image_url,created_at) VALUES (145,36,'SESSION','반려동물 구강관리 특강','짖음, 분리불안, 공격성 등 문제행동의 원인과 교정 방법을 실제 사례와 함께 안내합니다.','2024-10-07 00:00:00','2024-10-07 02:00:00',191, 'C\\pupoo_workspace\\uploads\\event_program\\session_default.jpg','2024-09-25 09:00:00');
