INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (1,'김동훈','서울대학교 수의과대학 교수, 반려동물 내과학 전문. 15년간 소동물 임상 경험, KBS 생로병사의 비밀 자문위원.','2023-03-15 10:00:00','dh.kim@snu.vet.example','010-2100-0001',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (2,'이수진','동물행동학 박사, 반려견 행동교정 전문가. 저서: 강아지 마음 읽기, 반려견 행동의 이해. SBS 동물농장 출연.','2023-03-15 10:00:00','sj.lee@behavior.example','010-2100-0002',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (3,'박정우','한국반려동물영양학회 회장, 사료 성분 분석 및 맞춤 영양 설계 전문. 20년 경력의 수의영양학 전문가.','2023-03-15 10:00:00','jw.park@nutrition.example','010-2100-0003',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (4,'최유진','펫테크 스타트업 CEO, IoT 기반 반려동물 건강관리 솔루션 개발. 2023년 CES Innovation Award 수상.','2023-03-15 10:00:00','yj.choi@pettech.example','010-2100-0004',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (5,'정하나','동물보호시민단체 사무국장, 유기동물 구조 및 입양 문화 확산 활동가. 동물보호법 개정 정책 자문위원.','2023-03-15 10:00:00','hn.jung@animalrights.example','010-2100-0005',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (6,'강민서','반려견 훈련사(KKC 1급), 어질리티 국제심판. 아시아 어질리티 챔피언십 한국 대표팀 코치.','2023-03-15 10:00:00','ms.kang@agility.example','010-2100-0006',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (7,'윤채영','펫 그루머 마스터(일본 JKC 인증), 15년 경력의 쇼그루밍 전문가. 아시아 그루밍 대회 심사위원.','2023-03-15 10:00:00','cy.yoon@grooming.example','010-2100-0007',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (8,'한성호','동물재활의학 전문 수의사, 반려동물 물리치료 및 재활 분야 10년 경력. 슬개골/고관절 재활 치료 다수 경험.','2023-03-15 10:00:00','sh.han@rehab.example','010-2100-0008',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (9,'서지원','반려동물 심리상담사, 펫로스 증후군 전문 상담. 저서: 무지개다리를 건넌 너에게. 반려동물 심리학 강의 다수.','2023-03-15 10:00:00','jw.seo@petpsych.example','010-2100-0009',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (10,'오태현','한국 켄넬클럽 심사위원, 도그쇼 및 콘테스트 심사 20년 경력. 견종 표준 심사 및 브리딩 컨설팅 전문가.','2023-03-15 10:00:00','th.oh@kennel.example','010-2100-0010',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (11,'임보라','반려동물 한의학 전문 수의사, 침구 및 한약 치료 전문. 동서양 통합 수의학 연구소 소장.','2023-03-15 10:00:00','br.lim@vetherb.example','010-2100-0011',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (12,'황예슬','동물매개심리치료사, 어린이-반려동물 교감 프로그램 개발. 서울시 교육청 동물매개교육 자문위원.','2023-03-15 10:00:00','ys.hwang@aat.example','010-2100-0012',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (13,'조민기','수의외과 전문의, 정형외과 수술 및 응급의학 전문. 대한수의사회 학술이사, 수의응급의학 교과서 공저.','2023-03-15 10:00:00','mk.cho@vetsurg.example','010-2100-0013',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (14,'배수현','반려동물 법률 전문 변호사, 동물보호법/펫보험 분쟁 전문. 동물권 관련 법률 자문 및 정책 제안 활동.','2023-03-15 10:00:00','sh.bae@petlaw.example','010-2100-0014',NULL);
INSERT INTO speakers (speaker_id,speaker_name,speaker_bio,created_at,speaker_email,speaker_phone,deleted_at) VALUES (15,'남도윤','반려견 수중재활 전문가, 하이드로테라피스트. 국내 최초 반려동물 수중재활센터 설립, 재활 프로그램 개발.','2023-03-15 10:00:00','dy.nam@aquavet.example','010-2100-0015',NULL);
