INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (1,'GLOBAL',NULL,'푸푸 서비스 오픈 안내','안녕하세요, 반려동물 통합 플랫폼 푸푸가 정식 오픈했습니다! 회원가입 시 1,000원 적립금을 드리며, 첫 행사 참가 시 10% 할인 쿠폰을 제공합니다. 많은 관심 부탁드립니다.','N',1,'PUBLISHED',1,252,'2023-03-01 10:00:00','2023-03-01 10:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (2,'GLOBAL',NULL,'개인정보처리방침 변경 안내','2023년 7월 1일부로 개인정보처리방침이 변경됩니다. 주요 변경사항: 마케팅 목적 정보활용 동의 절차 강화, 개인정보 보관기간 명확화. 전문은 앱 내 공지사항에서 확인하실 수 있습니다.','N',1,'PUBLISHED',1,78,'2023-06-25 09:00:00','2023-06-25 09:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (3,'GLOBAL',NULL,'앱 버전 2.0 업데이트 안내','더 편리해진 푸푸 앱 2.0이 출시되었습니다! QR 입장 기능 개선, 실시간 혼잡도 확인, 나의 행사 일정 관리 등 새로운 기능을 만나보세요.','N',0,'PUBLISHED',1,2340,'2023-09-15 14:00:00','2023-09-15 14:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (4,'GLOBAL',NULL,'서버 정기 점검 안내 (1/15)','원활한 서비스를 위해 아래와 같이 서버 점검을 실시합니다. 점검 시간: 2024년 1월 15일 02:00~06:00 (약 4시간). 점검 중 서비스 이용이 제한될 수 있습니다.','N',0,'PUBLISHED',1,2733,'2024-01-10 10:00:00','2024-01-10 10:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (5,'GLOBAL',NULL,'2024년 연간 행사 스케줄 공개','올해도 다양한 행사를 준비했습니다! 1분기: 서울 펫페어, 부산 독페스타 / 2분기: 경기 킨텍스 펫쇼, 제주 힐링캠프 / 3분기: 여름 특별 워터파크 이벤트 / 4분기: 연말 챌린지 대회. 사전등록 시 할인 혜택이 있습니다!','N',1,'PUBLISHED',1,980,'2024-02-20 09:00:00','2024-02-20 09:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (6,'GLOBAL',NULL,'카카오페이 결제 오류 안내 및 조치','현재 카카오페이 결제 시 일부 오류가 발생하고 있습니다. 원인 파악 중이며, 긴급 복구 작업을 진행하고 있습니다. 불편을 드려 대단히 죄송합니다.','N',1,'PUBLISHED',1,147,'2024-05-03 16:00:00','2024-05-03 16:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (7,'GLOBAL',NULL,'게시판 운영 정책 변경 안내','건전한 커뮤니티 운영을 위해 게시판 정책을 일부 변경합니다. 광고성 게시글 즉시 삭제, 비방/욕설 포함 게시글 블라인드 처리, 3회 이상 경고 시 게시 제한. 모두가 즐거운 커뮤니티를 만들어주세요!','N',0,'PUBLISHED',1,2714,'2024-08-01 10:00:00','2024-08-01 10:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (8,'GLOBAL',NULL,'추석 연휴 고객센터 운영 안내','추석 연휴 기간 고객센터 운영을 안내드립니다. 휴무 기간: 9월 15일~18일. 긴급 문의는 앱 내 1:1 문의로 남겨주시면 연휴 후 순차 답변드리겠습니다.','N',0,'PUBLISHED',1,1891,'2024-09-10 09:00:00','2024-09-10 09:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (9,'GLOBAL',NULL,'푸푸 앱 3.0 업데이트 - AI 추천 기능 추가','반려동물 맞춤 행사 추천, AI 건강 체크리스트, 커뮤니티 관심사 기반 피드 등 새로운 기능이 추가되었습니다. 지금 업데이트하고 체험해보세요!','N',0,'PUBLISHED',1,1658,'2025-03-01 10:00:00','2025-03-01 10:00:00');
INSERT INTO notices (notice_id,scope,event_id,notice_title,content,file_attached,is_pinned,status,created_by_admin_id,view_count,created_at,updated_at) VALUES (10,'GLOBAL',NULL,'2025년 신규 행사 파트너 모집','2025년 행사에 참여할 업체를 모집합니다. 부스 참가, 프로그램 운영, 스폰서십 등 다양한 협업 기회가 있습니다. 관심 있는 업체는 파트너 페이지에서 신청해주세요.','N',0,'PUBLISHED',1,1166,'2025-06-15 14:00:00','2025-06-15 14:00:00');
