INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (15,2,16,'첫 펫행사인데 감동이었어요','반려동물 행동학 세미나를 들었는데, 평소 궁금했던 문제행동 교정법을 알 수 있어서 정말 유익했어요. 강연자분이 실제 사례를 들어 설명해주셔서 이해가 잘 됐습니다.',5,87,'2023-08-14 01:00:00','2023-08-14 01:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (16,2,61,'주차가 좀 불편했지만 행사는 최고','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',5,291,'2023-08-18 12:00:00','2023-08-18 12:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (17,2,42,'알찬 프로그램 가득!','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',5,47,'2023-08-16 16:00:00','2023-08-16 16:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (18,3,95,'내년에도 꼭 올게요!','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',5,78,'2023-07-24 04:00:00','2023-07-24 04:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (19,3,49,'가족 나들이로 딱이에요','행사장 도착하자마자 우리 보리가 신나서 꼬리 흔들며 뛰어다녔어요. 부스마다 시식 간식도 많고, 건강 체크도 무료로 해줘서 너무 좋았어요. 특히 어질리티 체험은 처음이었는데 우리 애가 의외로 잘하더라고요! 다음에도 꼭 올게요.',3,194,'2023-07-21 12:00:00','2023-07-21 12:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (20,3,88,'재방문 의사 200%','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',5,197,'2023-07-26 08:00:00','2023-07-26 08:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (21,3,83,'사진 많이 찍었어요 기념사진 포토존 좋아요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',4,9,'2023-07-26 00:00:00','2023-07-26 00:00:00',0,1,'PUBLIC');
