INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (23,3,100,'생각보다 훨씬 좋았어요','전체적으로 괜찮았는데, 소형견 구역과 대형견 구역이 분리가 안 돼서 좀 위험한 순간이 있었어요. 그리고 화장실이 부족하고 줄이 길었어요. 프로그램 자체는 좋았지만 운영 면에서 개선이 필요해 보여요.',5,197,'2023-07-23 23:00:00','2023-07-23 23:00:00',0,1,'PUBLIC');
