INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (38,5,52,'알찬 프로그램 가득!','아이 둘이랑 강아지 데리고 갔는데, 아이들도 강아지도 다 즐거워했어요. 키즈존이 따로 있어서 안심이었고, 먹거리도 다양해서 온 가족이 만족한 나들이였습니다.',4,217,'2023-06-13 09:00:00','2023-06-13 09:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (39,5,67,'첫 펫행사인데 감동이었어요','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',3,43,'2023-06-13 19:00:00','2023-06-13 19:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (40,5,17,'우리 강아지가 제일 좋아한 행사','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',4,39,'2023-06-14 03:00:00','2023-06-14 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (41,5,99,'우리 강아지가 제일 좋아한 행사','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',4,224,'2023-06-16 16:00:00','2023-06-16 16:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (42,5,48,'전문 세미나가 유익했어요','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',5,253,'2023-06-13 23:00:00','2023-06-13 23:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (43,6,44,'가족 나들이로 딱이에요','솔직히 기대 안 하고 갔는데 규모가 생각보다 크고 볼거리가 많았어요. 강아지 패션쇼가 하이라이트였는데, 다들 귀엽게 차려입고 나와서 웃음이 끊이지 않았습니다. 한 가지 아쉬운 점은 그늘이 부족해서 더웠어요.',4,31,'2023-12-04 03:00:00','2023-12-04 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (44,6,76,'준비가 정말 꼼꼼하더라고요','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',4,97,'2023-11-30 19:00:00','2023-11-30 19:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (45,6,69,'주차가 좀 불편했지만 행사는 최고','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',5,125,'2023-11-30 07:00:00','2023-11-30 07:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (46,6,82,'정말 잘 다녀왔습니다!','전체적으로 괜찮았는데, 소형견 구역과 대형견 구역이 분리가 안 돼서 좀 위험한 순간이 있었어요. 그리고 화장실이 부족하고 줄이 길었어요. 프로그램 자체는 좋았지만 운영 면에서 개선이 필요해 보여요.',3,212,'2023-12-01 21:00:00','2023-12-01 21:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (47,6,72,'정말 잘 다녀왔습니다!','전체적으로 괜찮았는데, 소형견 구역과 대형견 구역이 분리가 안 돼서 좀 위험한 순간이 있었어요. 그리고 화장실이 부족하고 줄이 길었어요. 프로그램 자체는 좋았지만 운영 면에서 개선이 필요해 보여요.',5,60,'2023-12-01 01:00:00','2023-12-01 01:00:00',0,1,'PUBLIC');
