INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (66,9,33,'첫 펫행사인데 감동이었어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',5,60,'2023-12-13 00:00:00','2023-12-13 00:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (67,9,70,'첫 펫행사인데 감동이었어요','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',5,69,'2023-12-14 13:00:00','2023-12-14 13:00:00',0,1,'PUBLIC');
