INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (69,11,36,'행사장이 넓어서 쾌적했어요','반려동물 행동학 세미나를 들었는데, 평소 궁금했던 문제행동 교정법을 알 수 있어서 정말 유익했어요. 강연자분이 실제 사례를 들어 설명해주셔서 이해가 잘 됐습니다.',5,39,'2023-12-10 16:00:00','2023-12-10 16:00:00',0,1,'PUBLIC');
