INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (94,16,38,'준비가 정말 꼼꼼하더라고요','행사장 도착하자마자 우리 보리가 신나서 꼬리 흔들며 뛰어다녔어요. 부스마다 시식 간식도 많고, 건강 체크도 무료로 해줘서 너무 좋았어요. 특히 어질리티 체험은 처음이었는데 우리 애가 의외로 잘하더라고요! 다음에도 꼭 올게요.',5,143,'2023-09-13 12:00:00','2023-09-13 12:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (95,16,58,'간식 부스에서 너무 많이 샀어요ㅋㅋ','포토존이 5개나 있었는데 다 예뻤어요! 꽃밭 배경, 해변 배경, 숲속 배경 등 다양해서 사진을 정말 많이 찍었네요. 인화 서비스도 있어서 현장에서 바로 뽑았어요.',5,30,'2023-09-12 10:00:00','2023-09-12 10:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (96,17,74,'첫 펫행사인데 감동이었어요','전체적으로 괜찮았는데, 소형견 구역과 대형견 구역이 분리가 안 돼서 좀 위험한 순간이 있었어요. 그리고 화장실이 부족하고 줄이 길었어요. 프로그램 자체는 좋았지만 운영 면에서 개선이 필요해 보여요.',3,95,'2023-05-04 02:00:00','2023-05-04 02:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (97,17,72,'간식 부스에서 너무 많이 샀어요ㅋㅋ','간식 부스 때문에 지갑이 텅텅ㅋㅋ 수제 간식, 유기농 사료 샘플, 각종 영양제까지... 원래 구경만 하려고 했는데 결국 양손 가득 들고 나왔습니다. 하지만 후회없어요!',3,258,'2023-04-30 17:00:00','2023-04-30 17:00:00',0,1,'PUBLIC');
