INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (121,19,5,'사진 많이 찍었어요 기념사진 포토존 좋아요','간식 부스 때문에 지갑이 텅텅ㅋㅋ 수제 간식, 유기농 사료 샘플, 각종 영양제까지... 원래 구경만 하려고 했는데 결국 양손 가득 들고 나왔습니다. 하지만 후회없어요!',3,234,'2024-03-20 12:00:00','2024-03-20 12:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (122,19,91,'행사장이 넓어서 쾌적했어요','반려동물 행동학 세미나를 들었는데, 평소 궁금했던 문제행동 교정법을 알 수 있어서 정말 유익했어요. 강연자분이 실제 사례를 들어 설명해주셔서 이해가 잘 됐습니다.',5,74,'2024-03-22 03:00:00','2024-03-22 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (123,20,79,'생각보다 훨씬 좋았어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',5,126,'2024-03-27 17:00:00','2024-03-27 17:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (124,20,86,'정말 잘 다녀왔습니다!','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',5,229,'2024-03-29 18:00:00','2024-03-29 18:00:00',0,1,'PUBLIC');
