INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (149,22,9,'준비가 정말 꼼꼼하더라고요','포토존이 5개나 있었는데 다 예뻤어요! 꽃밭 배경, 해변 배경, 숲속 배경 등 다양해서 사진을 정말 많이 찍었네요. 인화 서비스도 있어서 현장에서 바로 뽑았어요.',5,99,'2024-09-23 15:00:00','2024-09-23 15:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (150,23,76,'알찬 프로그램 가득!','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',4,76,'2024-05-01 03:00:00','2024-05-01 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (151,23,15,'정말 잘 다녀왔습니다!','탁 트인 공간에서 진행돼서 답답하지 않았어요. 소형견 놀이터, 대형견 런, 수영장까지 있어서 우리 애가 하루 종일 뛰놀았네요. 집에 가니까 바로 잠들었어요ㅋㅋ',4,133,'2024-05-01 07:00:00','2024-05-01 07:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (152,23,82,'아쉬운 점이 좀 있었어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',4,147,'2024-05-02 16:00:00','2024-05-02 16:00:00',0,1,'PUBLIC');
