INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (154,23,18,'알찬 프로그램 가득!','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',5,123,'2024-04-29 07:00:00','2024-04-29 07:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (155,23,87,'주차가 좀 불편했지만 행사는 최고','탁 트인 공간에서 진행돼서 답답하지 않았어요. 소형견 놀이터, 대형견 런, 수영장까지 있어서 우리 애가 하루 종일 뛰놀았네요. 집에 가니까 바로 잠들었어요ㅋㅋ',4,86,'2024-04-30 21:00:00','2024-04-30 21:00:00',0,1,'PUBLIC');
