INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (159,24,63,'간식 부스에서 너무 많이 샀어요ㅋㅋ','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',4,112,'2024-11-17 11:00:00','2024-11-17 11:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (160,24,92,'내년에도 꼭 올게요!','반려동물 행동학 세미나를 들었는데, 평소 궁금했던 문제행동 교정법을 알 수 있어서 정말 유익했어요. 강연자분이 실제 사례를 들어 설명해주셔서 이해가 잘 됐습니다.',4,280,'2024-11-16 09:00:00','2024-11-16 09:00:00',0,1,'PUBLIC');
