INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (177,25,76,'전문 세미나가 유익했어요','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',5,107,'2024-10-27 10:00:00','2024-10-27 10:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (178,25,40,'아쉬운 점이 좀 있었어요','탁 트인 공간에서 진행돼서 답답하지 않았어요. 소형견 놀이터, 대형견 런, 수영장까지 있어서 우리 애가 하루 종일 뛰놀았네요. 집에 가니까 바로 잠들었어요ㅋㅋ',5,164,'2024-10-25 07:00:00','2024-10-25 07:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (179,25,54,'준비가 정말 꼼꼼하더라고요','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',2,204,'2024-10-28 07:00:00','2024-10-28 07:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (180,26,78,'재방문 의사 200%','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',4,273,'2024-08-02 02:00:00','2024-08-02 02:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (181,26,42,'첫 펫행사인데 감동이었어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',4,12,'2024-08-02 13:00:00','2024-08-02 13:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (182,26,46,'전문 세미나가 유익했어요','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',5,12,'2024-08-06 16:00:00','2024-08-06 16:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (183,26,68,'전문 세미나가 유익했어요','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',5,17,'2024-08-03 19:00:00','2024-08-03 19:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (184,26,33,'재방문 의사 200%','아이 둘이랑 강아지 데리고 갔는데, 아이들도 강아지도 다 즐거워했어요. 키즈존이 따로 있어서 안심이었고, 먹거리도 다양해서 온 가족이 만족한 나들이였습니다.',5,182,'2024-07-31 02:00:00','2024-07-31 02:00:00',0,1,'PUBLIC');
