INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (191,27,26,'주차가 좀 불편했지만 행사는 최고','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',3,205,'2024-11-10 12:00:00','2024-11-10 12:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (192,27,72,'정말 잘 다녀왔습니다!','전체적으로 괜찮았는데, 소형견 구역과 대형견 구역이 분리가 안 돼서 좀 위험한 순간이 있었어요. 그리고 화장실이 부족하고 줄이 길었어요. 프로그램 자체는 좋았지만 운영 면에서 개선이 필요해 보여요.',2,218,'2024-11-07 12:00:00','2024-11-07 12:00:00',0,1,'PUBLIC');
