INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (238,34,77,'행사장이 넓어서 쾌적했어요','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',5,286,'2024-09-29 13:00:00','2024-09-29 13:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (239,34,49,'알찬 프로그램 가득!','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',5,65,'2024-10-04 03:00:00','2024-10-04 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (240,35,70,'주차가 좀 불편했지만 행사는 최고','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',4,37,'2024-02-27 01:00:00','2024-02-27 01:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (241,35,80,'행사장이 넓어서 쾌적했어요','행사장 도착하자마자 우리 보리가 신나서 꼬리 흔들며 뛰어다녔어요. 부스마다 시식 간식도 많고, 건강 체크도 무료로 해줘서 너무 좋았어요. 특히 어질리티 체험은 처음이었는데 우리 애가 의외로 잘하더라고요! 다음에도 꼭 올게요.',5,56,'2024-02-23 22:00:00','2024-02-23 22:00:00',0,1,'PUBLIC');
