INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (259,37,60,'준비가 정말 꼼꼼하더라고요','솔직히 기대 안 하고 갔는데 규모가 생각보다 크고 볼거리가 많았어요. 강아지 패션쇼가 하이라이트였는데, 다들 귀엽게 차려입고 나와서 웃음이 끊이지 않았습니다. 한 가지 아쉬운 점은 그늘이 부족해서 더웠어요.',2,184,'2025-09-09 13:00:00','2025-09-09 13:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (260,37,89,'행사장이 넓어서 쾌적했어요','솔직히 기대 안 하고 갔는데 규모가 생각보다 크고 볼거리가 많았어요. 강아지 패션쇼가 하이라이트였는데, 다들 귀엽게 차려입고 나와서 웃음이 끊이지 않았습니다. 한 가지 아쉬운 점은 그늘이 부족해서 더웠어요.',3,107,'2025-09-09 03:00:00','2025-09-09 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (261,38,60,'전문 세미나가 유익했어요','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',3,229,'2025-11-08 22:00:00','2025-11-08 22:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (262,38,97,'아쉬운 점이 좀 있었어요','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',5,244,'2025-11-15 01:00:00','2025-11-15 01:00:00',0,1,'PUBLIC');
