INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (287,41,17,'행사장이 넓어서 쾌적했어요','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',5,165,'2025-07-15 09:00:00','2025-07-15 09:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (288,41,46,'간식 부스에서 너무 많이 샀어요ㅋㅋ','행사장 도착하자마자 우리 보리가 신나서 꼬리 흔들며 뛰어다녔어요. 부스마다 시식 간식도 많고, 건강 체크도 무료로 해줘서 너무 좋았어요. 특히 어질리티 체험은 처음이었는데 우리 애가 의외로 잘하더라고요! 다음에도 꼭 올게요.',3,100,'2025-07-19 15:00:00','2025-07-19 15:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (289,42,94,'주차가 좀 불편했지만 행사는 최고','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',5,248,'2025-01-19 21:00:00','2025-01-19 21:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (290,42,51,'준비가 정말 꼼꼼하더라고요','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',4,237,'2025-01-19 14:00:00','2025-01-19 14:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (291,42,11,'첫 펫행사인데 감동이었어요','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',5,176,'2025-01-20 10:00:00','2025-01-20 10:00:00',0,1,'PUBLIC');
