INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (302,43,16,'부스가 다양해서 좋았어요','솔직히 기대 안 하고 갔는데 규모가 생각보다 크고 볼거리가 많았어요. 강아지 패션쇼가 하이라이트였는데, 다들 귀엽게 차려입고 나와서 웃음이 끊이지 않았습니다. 한 가지 아쉬운 점은 그늘이 부족해서 더웠어요.',5,13,'2025-01-07 16:00:00','2025-01-07 16:00:00',0,1,'PUBLIC');
