INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (314,45,38,'아쉬운 점이 좀 있었어요','간식 부스 때문에 지갑이 텅텅ㅋㅋ 수제 간식, 유기농 사료 샘플, 각종 영양제까지... 원래 구경만 하려고 했는데 결국 양손 가득 들고 나왔습니다. 하지만 후회없어요!',4,267,'2025-07-22 02:00:00','2025-07-22 02:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (315,45,83,'아쉬운 점이 좀 있었어요','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',3,181,'2025-07-23 00:00:00','2025-07-23 00:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (316,45,99,'생각보다 훨씬 좋았어요','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',4,296,'2025-07-22 05:00:00','2025-07-22 05:00:00',0,1,'PUBLIC');
