INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (318,46,8,'우리 강아지가 제일 좋아한 행사','아이 둘이랑 강아지 데리고 갔는데, 아이들도 강아지도 다 즐거워했어요. 키즈존이 따로 있어서 안심이었고, 먹거리도 다양해서 온 가족이 만족한 나들이였습니다.',3,143,'2025-06-09 09:00:00','2025-06-09 09:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (319,46,76,'사진 많이 찍었어요 기념사진 포토존 좋아요','탁 트인 공간에서 진행돼서 답답하지 않았어요. 소형견 놀이터, 대형견 런, 수영장까지 있어서 우리 애가 하루 종일 뛰놀았네요. 집에 가니까 바로 잠들었어요ㅋㅋ',4,216,'2025-06-09 19:00:00','2025-06-09 19:00:00',0,1,'PUBLIC');
