INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (321,46,21,'주차가 좀 불편했지만 행사는 최고','포토존이 5개나 있었는데 다 예뻤어요! 꽃밭 배경, 해변 배경, 숲속 배경 등 다양해서 사진을 정말 많이 찍었네요. 인화 서비스도 있어서 현장에서 바로 뽑았어요.',4,208,'2025-06-13 15:00:00','2025-06-13 15:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (322,46,81,'아쉬운 점이 좀 있었어요','행사장 도착하자마자 우리 보리가 신나서 꼬리 흔들며 뛰어다녔어요. 부스마다 시식 간식도 많고, 건강 체크도 무료로 해줘서 너무 좋았어요. 특히 어질리티 체험은 처음이었는데 우리 애가 의외로 잘하더라고요! 다음에도 꼭 올게요.',5,107,'2025-06-13 05:00:00','2025-06-13 05:00:00',0,1,'PUBLIC');
