INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (330,47,57,'생각보다 훨씬 좋았어요','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',4,268,'2025-12-11 05:00:00','2025-12-11 05:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (331,47,55,'정말 잘 다녀왔습니다!','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',5,46,'2025-12-15 02:00:00','2025-12-15 02:00:00',0,1,'PUBLIC');
