INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (342,48,70,'가족 나들이로 딱이에요','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',5,77,'2025-12-24 21:00:00','2025-12-24 21:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (343,48,37,'우리 강아지가 제일 좋아한 행사','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',4,71,'2025-12-24 06:00:00','2025-12-24 06:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (344,48,68,'우리 강아지가 제일 좋아한 행사','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',3,249,'2025-12-27 03:00:00','2025-12-27 03:00:00',0,1,'PUBLIC');
