INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (369,51,8,'사진 많이 찍었어요 기념사진 포토존 좋아요','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',4,252,'2025-01-11 13:00:00','2025-01-11 13:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (370,51,81,'내년에도 꼭 올게요!','탁 트인 공간에서 진행돼서 답답하지 않았어요. 소형견 놀이터, 대형견 런, 수영장까지 있어서 우리 애가 하루 종일 뛰놀았네요. 집에 가니까 바로 잠들었어요ㅋㅋ',5,157,'2025-01-11 01:00:00','2025-01-11 01:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (371,52,30,'재방문 의사 200%','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',5,110,'2025-08-24 10:00:00','2025-08-24 10:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (372,52,8,'가족 나들이로 딱이에요','부스가 100개 가까이 있었는데 시식 부스, 체험 부스, 판매 부스 골고루 있어서 지루할 틈이 없었어요. 특히 수제 간식 부스에서 산 닭가슴살 져키를 우리 애가 엄청 좋아해요.',4,242,'2025-08-26 07:00:00','2025-08-26 07:00:00',0,1,'PUBLIC');
