INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (395,55,31,'사진 많이 찍었어요 기념사진 포토존 좋아요','아이 둘이랑 강아지 데리고 갔는데, 아이들도 강아지도 다 즐거워했어요. 키즈존이 따로 있어서 안심이었고, 먹거리도 다양해서 온 가족이 만족한 나들이였습니다.',5,86,'2026-02-13 19:00:00','2026-02-13 19:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (396,55,92,'사진 많이 찍었어요 기념사진 포토존 좋아요','두 번째 방문인데 전보다 더 좋아졌어요! 부스 배치가 깔끔해졌고, 휴식 공간도 늘었더라고요. 물 급수대도 곳곳에 있어서 편했어요. 내년에는 친구들도 데려올 예정입니다.',5,167,'2026-02-16 06:00:00','2026-02-16 06:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (397,55,54,'행사장이 넓어서 쾌적했어요','반려동물 행동학 세미나를 들었는데, 평소 궁금했던 문제행동 교정법을 알 수 있어서 정말 유익했어요. 강연자분이 실제 사례를 들어 설명해주셔서 이해가 잘 됐습니다.',5,176,'2026-02-10 13:00:00','2026-02-10 13:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (398,55,30,'주차가 좀 불편했지만 행사는 최고','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',5,23,'2026-02-16 03:00:00','2026-02-16 03:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (399,56,14,'재방문 의사 200%','포토존이 5개나 있었는데 다 예뻤어요! 꽃밭 배경, 해변 배경, 숲속 배경 등 다양해서 사진을 정말 많이 찍었네요. 인화 서비스도 있어서 현장에서 바로 뽑았어요.',3,298,'2026-02-14 05:00:00','2026-02-14 05:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (400,56,26,'가족 나들이로 딱이에요','반려견 키운 지 1년 됐는데 이런 행사는 처음이었어요. 같은 반려인분들과 이야기도 나누고, 새로운 용품도 알게 되고 정말 유익했습니다. 무엇보다 우리 애가 행복해하는 모습에 제가 더 즐거웠어요.',5,113,'2026-02-13 23:00:00','2026-02-13 23:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (401,56,99,'우리 강아지가 제일 좋아한 행사','탁 트인 공간에서 진행돼서 답답하지 않았어요. 소형견 놀이터, 대형견 런, 수영장까지 있어서 우리 애가 하루 종일 뛰놀았네요. 집에 가니까 바로 잠들었어요ㅋㅋ',5,246,'2026-02-14 22:00:00','2026-02-14 22:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (402,56,84,'준비가 정말 꼼꼼하더라고요','간식 부스 때문에 지갑이 텅텅ㅋㅋ 수제 간식, 유기농 사료 샘플, 각종 영양제까지... 원래 구경만 하려고 했는데 결국 양손 가득 들고 나왔습니다. 하지만 후회없어요!',3,132,'2026-02-13 13:00:00','2026-02-13 13:00:00',0,1,'PUBLIC');
