INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (404,56,57,'알찬 프로그램 가득!','보통 낯가림이 심한 우리 콩이가 여기서는 꼬리 흔들며 다른 강아지들이랑 잘 놀더라고요! 환경이 편안해서 그런 것 같아요. 포토존에서 찍은 사진도 너무 이쁘고, 기념 발도장 찍기도 귀여웠어요.',5,274,'2026-02-13 14:00:00','2026-02-13 14:00:00',0,1,'PUBLIC');
