INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (424,59,65,'아쉬운 점이 좀 있었어요','프로그램이 시간대별로 잘 짜여있어서 하나도 빠짐없이 참여할 수 있었어요. 특히 수의사 건강 상담 코너에서 평소 궁금했던 것들 많이 물어봤는데, 친절하게 답변해주셨어요. 애견용품 할인도 짭짤했고요.',4,116,'2026-02-09 17:00:00','2026-02-09 17:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (425,59,77,'사진 많이 찍었어요 기념사진 포토존 좋아요','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',4,260,'2026-02-14 14:00:00','2026-02-14 14:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (426,59,79,'가족 나들이로 딱이에요','올해로 3회 연속 참가인데 매년 발전하는 게 느껴져요. 이번에는 야간 조명 산책 코스가 새로 생겼는데 분위기 진짜 좋았어요. 내년 일정 나오면 바로 등록할게요!',1,170,'2026-02-08 07:00:00','2026-02-08 07:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (427,59,62,'재방문 의사 200%','전체적으로 괜찮았는데, 소형견 구역과 대형견 구역이 분리가 안 돼서 좀 위험한 순간이 있었어요. 그리고 화장실이 부족하고 줄이 길었어요. 프로그램 자체는 좋았지만 운영 면에서 개선이 필요해 보여요.',5,168,'2026-02-07 21:00:00','2026-02-07 21:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (428,59,56,'정말 잘 다녀왔습니다!','세부적인 것까지 신경 쓴 느낌이었어요. 배변봉투 무료 제공, 급수대 배치, 긴급 수의사 대기 등 반려동물을 정말 배려한 행사라고 느꼈습니다. 운영진분들 고생 많으셨어요!',5,18,'2026-02-12 05:00:00','2026-02-12 05:00:00',0,1,'PUBLIC');
