INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (431,60,70,'내년에도 꼭 올게요!','포토존이 5개나 있었는데 다 예뻤어요! 꽃밭 배경, 해변 배경, 숲속 배경 등 다양해서 사진을 정말 많이 찍었네요. 인화 서비스도 있어서 현장에서 바로 뽑았어요.',2,204,'2026-02-13 05:00:00','2026-02-13 05:00:00',0,1,'PUBLIC');
INSERT INTO reviews (review_id,event_id,user_id,review_title,content,rating,view_count,created_at,updated_at,is_deleted,is_comment_enabled,review_status) VALUES (432,60,65,'간식 부스에서 너무 많이 샀어요ㅋㅋ','주차장이 부족해서 30분 넘게 헤맸어요... 결국 멀리 주차하고 걸어왔는데, 셔틀버스가 있었으면 좋겠어요. 그래도 행사 자체는 알차고 프로그램도 재밌어서 만족합니다.',4,275,'2026-02-15 10:00:00','2026-02-15 10:00:00',0,1,'PUBLIC');
