INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (1,48,'EVENT','행사 주차장 위치가 어디인가요','다음 주 서울 펫페어 가려고 하는데, 주차장 정확한 위치와 요금을 알고 싶습니다.','OPEN','2025-05-22 06:50:26','2025-05-22 06:50:26');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (2,62,'EVENT','대형견도 참가 가능한가요','저희 집 골든리트리버(35kg)인데 모든 프로그램 참여 가능한지 확인 부탁드립니다.','OPEN','2025-07-27 01:48:13','2025-07-27 01:48:13');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (3,95,'PAYMENT','결제가 중복으로 된 것 같습니다','카카오페이로 결제했는데 문자가 2번 왔어요. 확인 부탁드립니다.','CLOSED','2025-02-27 09:48:41','2025-02-27 09:48:41');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (4,20,'PAYMENT','결제 영수증 재발급 요청','지난달 결제한 행사비 영수증을 회사에 제출해야하는데 재발급이 가능한가요?','CLOSED','2023-11-30 13:17:14','2023-11-30 13:17:14');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (5,15,'REFUND','행사 취소로 인한 환불 요청','원래 예정된 행사가 취소되었다고 들었는데, 환불 절차가 어떻게 되나요?','CLOSED','2026-01-29 07:48:19','2026-01-29 07:48:19');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (6,87,'REFUND','부분 환불 가능한가요','행사 참가는 했는데 프로그램 1개가 취소되어서 해당 금액만 환불받고 싶습니다.','CLOSED','2025-03-09 21:36:44','2025-03-09 21:36:44');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (7,64,'ACCOUNT','닉네임 변경이 안 됩니다','설정에서 닉네임 변경하려고 하면 오류가 발생합니다. 확인 부탁드려요.','IN_PROGRESS','2023-04-14 00:43:49','2023-04-14 00:43:49');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (8,18,'ACCOUNT','탈퇴 후 재가입 가능한가요','계정을 탈퇴하려고 하는데, 나중에 같은 이메일로 재가입이 가능한지 궁금합니다.','CLOSED','2023-06-04 03:18:54','2023-06-04 03:18:54');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (9,10,'ACCOUNT','소셜 로그인 연동 해제 방법','카카오 연동을 네이버로 변경하고 싶은데 기존 연동 해제는 어떻게 하나요?','IN_PROGRESS','2025-07-04 03:32:53','2025-07-04 03:32:53');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (10,38,'OTHER','앱에서 알림이 안 와요','알림 설정은 켜져 있는데 행사 알림을 전혀 못 받고 있습니다. 확인 부탁드립니다.','OPEN','2025-08-16 00:15:23','2025-08-16 00:15:23');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (11,88,'OTHER','행사 사진 다운로드는 어디서 하나요','지난 행사 참여했는데, 공식 사진을 어디서 다운받을 수 있나요?','CLOSED','2025-07-27 06:54:16','2025-07-27 06:54:16');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (12,38,'EVENT','유모차 대여가 가능한가요','반려견 유모차를 안 가져갔는데, 현장에서 대여할 수 있나요?','CLOSED','2024-05-04 21:00:09','2024-05-04 21:00:09');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (13,66,'PAYMENT','결제 수단 변경이 가능한가요','카카오페이로 결제했는데 카드 결제로 변경하고 싶습니다. 가능한지요?','CLOSED','2025-08-03 22:02:13','2025-08-03 22:02:13');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (14,8,'ACCOUNT','비밀번호를 까먹었어요','이메일은 아는데 비밀번호가 기억이 안 나요. 재설정 메일이 안 오는 것 같은데...','CLOSED','2024-05-27 02:41:17','2024-05-27 02:41:17');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (15,36,'EVENT','반려묘도 참가 가능한 행사가 있나요','강아지 행사만 있는 것 같은데, 고양이도 참여할 수 있는 프로그램이 있나요?','CLOSED','2024-01-24 21:05:59','2024-01-24 21:05:59');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (16,61,'REFUND','환불 처리 기간이 얼마나 걸리나요','일주일 전에 환불 요청했는데 아직 처리가 안 된 것 같습니다.','CLOSED','2024-08-07 11:48:17','2024-08-07 11:48:17');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (17,56,'OTHER','행사 봉사자 지원하고 싶습니다','다음 행사에서 봉사활동을 하고 싶은데, 지원 방법이 있을까요?','IN_PROGRESS','2025-03-12 06:36:41','2025-03-12 06:36:41');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (18,57,'OTHER','QR코드가 인식이 안 됩니다','입장 QR코드를 스캔하려고 하면 계속 오류가 떠요. 어떡하죠?','IN_PROGRESS','2023-07-03 00:28:30','2023-07-03 00:28:30');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (19,15,'EVENT','우천시 행사 진행 여부','이번 주말 비 예보가 있는데, 야외 행사는 정상 진행되나요?','OPEN','2024-03-02 09:37:14','2024-03-02 09:37:14');
INSERT INTO inquiries (inquiry_id,user_id,category,inquiry_title,content,status,created_at,updated_at) VALUES (20,94,'PAYMENT','단체 할인이 있나요','5명이 같이 가려고 하는데 단체 할인 혜택이 있는지 궁금합니다.','OPEN','2025-05-23 11:41:23','2025-05-23 11:41:23');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (1,3,3,'안녕하세요, 결제 내역 확인 결과 중복 결제가 맞으며 자동 취소 처리 중입니다. 카카오페이 기준 1~3영업일 내 환불됩니다. 불편을 드려 죄송합니다.','2025-02-28 14:48:41');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (2,4,3,'안녕하세요! 결제 영수증 재발급은 마이페이지 > 결제내역에서 직접 다운로드 가능합니다. PDF 형식으로 제공되며, 추가 문의사항 있으시면 말씀해주세요.','2023-12-02 13:17:14');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (3,5,1,'안녕하세요, 행사 취소에 따른 환불은 결제하신 수단으로 자동 진행됩니다. 처리 기간은 카드결제 3~5영업일, 카카오페이 1~3영업일 소요됩니다.','2026-01-30 04:48:19');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (4,6,3,'안녕하세요! 프로그램 단위 부분 환불은 현재 시스템상 어렵습니다. 다만 해당 프로그램 취소 건에 한해 적립금으로 보상해드리고 있습니다. 자세한 사항은 개별 안내드리겠습니다.','2025-03-10 19:36:44');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (5,7,3,'안녕하세요, 닉네임 변경 오류 확인 결과 특수문자 포함 시 에러가 발생하는 버그를 확인했습니다. 현재 수정 중이며, 임시로 한글/영문/숫자만 사용해주시면 정상 작동합니다.','2023-04-15 18:43:49');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (6,8,1,'안녕하세요! 탈퇴 후 동일 이메일로 재가입은 30일 경과 후 가능합니다. 탈퇴 시 기존 활동내역(리뷰, 게시글 등)은 복구되지 않으니 신중하게 결정해주세요.','2023-06-04 19:18:54');
INSERT INTO inquiry_answers (answer_id,inquiry_id,admin_id,content,created_at) VALUES (7,9,3,'안녕하세요, 소셜 연동 해제는 마이페이지 > 계정설정 > 소셜 연동 관리에서 가능합니다. 기존 카카오 연동 해제 후 네이버 연동을 새로 추가해주시면 됩니다.','2025-07-05 14:32:53');
