INSERT INTO notification (notification_id,type,notification_title,content) VALUES (1,'SYSTEM','푸푸에 오신 것을 환영합니다!','반려동물과 함께하는 특별한 경험, 푸푸에서 시작하세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (2,'EVENT','입장 QR코드가 발급되었습니다','마이페이지에서 QR코드를 확인해주세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (3,'NOTICE','새로운 공지사항이 등록되었습니다','중요한 안내사항을 확인해주세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (4,'PAYMENT','결제가 완료되었습니다','결제 내역은 마이페이지에서 확인할 수 있습니다.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (5,'APPLY','행사 신청이 승인되었습니다','행사 참가가 확정되었습니다. QR코드를 확인해주세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (6,'SYSTEM','비밀번호 변경 완료','비밀번호가 성공적으로 변경되었습니다.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (7,'EVENT','행사 시작 하루 전입니다!','내일 행사가 시작됩니다. 준비물을 확인해주세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (8,'PAYMENT','환불 처리가 완료되었습니다','환불 금액이 원래 결제 수단으로 반환됩니다.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (9,'APPLY','프로그램 참가 확정 안내','신청하신 프로그램 참가가 확정되었습니다.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (10,'SYSTEM','프로필 업데이트 완료','프로필 정보가 성공적으로 수정되었습니다.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (11,'EVENT','행사가 종료되었습니다','참가해주셔서 감사합니다. 후기를 남겨주세요!');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (12,'NOTICE','서버 점검 완료 안내','예정된 서버 점검이 완료되었습니다. 정상 이용 가능합니다.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (13,'PAYMENT','결제 실패 안내','결제 처리 중 오류가 발생했습니다. 다시 시도해주세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (14,'APPLY','대기 순번 안내','현재 대기 순서가 되었습니다. 10분 내 입장해주세요.');
INSERT INTO notification (notification_id,type,notification_title,content) VALUES (15,'SYSTEM','오랜만에 방문해주셨네요!','새로운 행사가 준비되어 있습니다. 확인해보세요.');
